import sys
it = iter(sys.stdin.read().split())
n = int(next(it))

def count_good_numbers(num):
    count = 0
    for i in range(1, num + 1):
        str_i = str(i)
        digit_count = {}
        for digit in str_i:
            if digit in digit_count:
                digit_count[digit] += 1
            else:
                digit_count[digit] = 1
        if all(count == 3 for count in digit_count.values()):
            count += 1
    return count

result = count_good_numbers(n)
print(result)

