int main(){
    int n;
    if(!(cin >> n)) return 0;
    int count = 0;
    for(int i = 1; i <= n; i++) {
        string str_i = to_string(i);
        unordered_map<char, int> digit_count;
        for(char digit : str_i) {
            if(digit_count.find(digit) != digit_count.end()) {
                digit_count[digit]++;
            } else {
                digit_count[digit] = 1;
            }
        }
        bool is_good = true;
        for(auto& pair : digit_count) {
            if(pair.second != 3) {
                is_good = false;
                break;
            }
        }
        if(is_good) count++;
    }
    cout << count << endl;
    return 0;
}
